    fn draw(&self) {
        print!("B");
    }
}

impl Draw for Slider {
    fn draw(&self) {
        print!("S");
    }
}

fn main() {
    let components: Vec<Box<dyn Draw>> = vec![
        Box::new(Slider),
        Box::new(Button),
        Box::new(Slider),
